/**
 * Purpose: Static preview navigation behavior for Nolan Showcase Theme X13.
 * WordPress role: None; mirrors the WordPress theme JavaScript.
 * Related files: preview.css and static HTML pages.
 * Important behavior: Accessible drawer and dropdown state without external dependencies.
 */
(function(){'use strict';var body=document.body;var toggle=document.querySelector('.menu-toggle');var nav=document.getElementById('primary-navigation');var parents=document.querySelectorAll('.primary-menu .has-dropdown');function drawer(open){if(!toggle||!nav)return;body.classList.toggle('menu-open',open);toggle.setAttribute('aria-expanded',open?'true':'false')}function close(){parents.forEach(function(i){i.classList.remove('is-open')})}if(toggle){toggle.addEventListener('click',function(){drawer(toggle.getAttribute('aria-expanded')!=='true')})}parents.forEach(function(item){var link=item.querySelector('a');if(!link)return;link.setAttribute('aria-haspopup','true');link.setAttribute('aria-expanded','false');link.addEventListener('click',function(e){if(window.matchMedia('(max-width: 980px)').matches){e.preventDefault();var open=item.classList.toggle('is-open');link.setAttribute('aria-expanded',open?'true':'false')}});item.addEventListener('mouseenter',function(){link.setAttribute('aria-expanded','true')});item.addEventListener('mouseleave',function(){link.setAttribute('aria-expanded','false');item.classList.remove('is-open')});item.addEventListener('focusin',function(){item.classList.add('is-open');link.setAttribute('aria-expanded','true')});item.addEventListener('focusout',function(){setTimeout(function(){if(!item.contains(document.activeElement)){item.classList.remove('is-open');link.setAttribute('aria-expanded','false')}},10)})});document.addEventListener('click',function(e){if(nav&&toggle&&!nav.contains(e.target)&&!toggle.contains(e.target)){drawer(false);close()}});document.addEventListener('keydown',function(e){if(e.key==='Escape'){drawer(false);close();if(toggle)toggle.focus()}})})();
